//! External agent workspace Tauri commands.
//!
//! @author kongweiguang

use tauri::{AppHandle, State};

use crate::{
    models::tool_registry::McpHttpServerStartRequest,
    services::external_agent_workspace::{
        ExternalAgentLaunchSpec, ExternalAgentWorkspaceService, ExternalAgentWorkspaceStatus,
        PrepareExternalAgentWorkspaceRequest,
    },
    state::AppState,
};

#[tauri::command]
pub fn get_external_agent_workspace_status(
    state: State<'_, AppState>,
) -> Result<ExternalAgentWorkspaceStatus, String> {
    let mcp_status = state
        .mcp_http_server()
        .status()
        .map_err(|error| error.to_string())?;
    let service = ExternalAgentWorkspaceService::new(
        state.paths().root.clone(),
        mcp_status.endpoint,
        mcp_status.running,
    );
    Ok(service.status())
}

#[tauri::command]
pub async fn prepare_external_agent_workspace(
    app: AppHandle,
    state: State<'_, AppState>,
    request: PrepareExternalAgentWorkspaceRequest,
) -> Result<ExternalAgentLaunchSpec, String> {
    let mcp_status = state
        .mcp_http_server()
        .start(app, Some(McpHttpServerStartRequest::default()))
        .await
        .map_err(|error| error.to_string())?;
    let service = ExternalAgentWorkspaceService::new(
        state.paths().root.clone(),
        mcp_status.endpoint,
        mcp_status.running,
    );
    service.prepare(&request).map_err(|error| error.to_string())
}

//! External agent workspace file preparation.
//!
//! @author kongweiguang

use std::{
    env,
    ffi::OsString,
    fs,
    path::{Path, PathBuf},
    time::{SystemTime, UNIX_EPOCH},
};

use serde::{Deserialize, Serialize};
use serde_json::{json, Map, Value};
use uuid::Uuid;

use crate::error::{AppError, AppResult};

const DEFAULT_MCP_ENDPOINT: &str = "http://127.0.0.1:37657/mcp";
const MANAGED_BLOCK_START: &str = "<!-- KERMINAL_EXTERNAL_AGENT_START -->";
const MANAGED_BLOCK_END: &str = "<!-- KERMINAL_EXTERNAL_AGENT_END -->";

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct PrepareExternalAgentWorkspaceRequest {
    pub agent_id: String,
    #[serde(default)]
    pub custom_command: Option<String>,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct ExternalAgentLaunchSpec {
    pub agent_id: String,
    pub title: String,
    pub shell: String,
    pub args: Vec<String>,
    pub cwd: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub env: Option<std::collections::BTreeMap<String, String>>,
    pub message: String,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct ExternalAgentWorkspaceStatus {
    pub workspace_dir: String,
    pub mcp_endpoint: String,
    pub mcp_server_running: bool,
    pub agents: ExternalAgentStatuses,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct ExternalAgentStatuses {
    pub codex: ExternalAgentStatus,
    pub claude: ExternalAgentStatus,
    pub custom: ExternalAgentStatus,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct ExternalAgentStatus {
    pub id: String,
    pub title: String,
    pub cli_command: String,
    pub installed: bool,
    pub config_ready: bool,
    pub config_path: String,
    pub status_detail: String,
}

#[derive(Debug, Clone)]
pub struct ExternalAgentWorkspaceService {
    workspace_dir: PathBuf,
    mcp_endpoint: String,
    mcp_server_running: bool,
}

impl ExternalAgentWorkspaceService {
    pub fn new(
        workspace_dir: impl Into<PathBuf>,
        mcp_endpoint: Option<String>,
        mcp_server_running: bool,
    ) -> Self {
        Self {
            workspace_dir: workspace_dir.into(),
            mcp_endpoint: mcp_endpoint.unwrap_or_else(|| DEFAULT_MCP_ENDPOINT.to_owned()),
            mcp_server_running,
        }
    }

    pub fn status(&self) -> ExternalAgentWorkspaceStatus {
        ExternalAgentWorkspaceStatus {
            workspace_dir: path_to_string(&self.workspace_dir),
            mcp_endpoint: self.mcp_endpoint.clone(),
            mcp_server_running: self.mcp_server_running,
            agents: ExternalAgentStatuses {
                codex: self.agent_status("codex", "Codex", "codex", self.codex_config_path()),
                claude: self.agent_status("claude", "Claude", "claude", self.claude_config_path()),
                custom: self.custom_agent_status(),
            },
        }
    }

    pub fn ensure_default_agent_files(&self) -> AppResult<()> {
        fs::create_dir_all(&self.workspace_dir)?;
        self.ensure_shared_instructions()?;
        self.ensure_codex_config()?;
        self.ensure_claude_files()?;
        Ok(())
    }

    pub fn prepare(
        &self,
        request: &PrepareExternalAgentWorkspaceRequest,
    ) -> AppResult<ExternalAgentLaunchSpec> {
        fs::create_dir_all(&self.workspace_dir)?;
        let agent_id = request.agent_id.trim();

        match agent_id {
            "codex" => {
                self.ensure_shared_instructions()?;
                self.ensure_codex_config()?;
                Ok(ExternalAgentLaunchSpec {
                    agent_id: "codex".to_owned(),
                    title: "Codex".to_owned(),
                    shell: "codex".to_owned(),
                    args: Vec::new(),
                    cwd: path_to_string(&self.workspace_dir),
                    env: None,
                    message: "Codex workspace files are ready.".to_owned(),
                })
            }
            "claude" => {
                self.ensure_shared_instructions()?;
                self.ensure_claude_files()?;
                Ok(ExternalAgentLaunchSpec {
                    agent_id: "claude".to_owned(),
                    title: "Claude".to_owned(),
                    shell: "claude".to_owned(),
                    args: Vec::new(),
                    cwd: path_to_string(&self.workspace_dir),
                    env: None,
                    message: "Claude workspace files are ready.".to_owned(),
                })
            }
            "custom" => {
                let command = request
                    .custom_command
                    .as_deref()
                    .map(str::trim)
                    .filter(|value| !value.is_empty())
                    .map(ToOwned::to_owned)
                    .ok_or_else(|| {
                        AppError::InvalidInput(
                            "Custom agent command is not configured. Enter a command before launch."
                                .to_owned(),
                        )
                    })?;
                let (shell, args) = parse_command_line(&command)?;
                Ok(ExternalAgentLaunchSpec {
                    agent_id: "custom".to_owned(),
                    title: "Custom Agent".to_owned(),
                    shell,
                    args,
                    cwd: path_to_string(&self.workspace_dir),
                    env: None,
                    message: "Custom agent workspace is ready.".to_owned(),
                })
            }
            other => Err(AppError::InvalidInput(format!(
                "Unsupported external agent: {other}"
            ))),
        }
    }

    fn agent_status(
        &self,
        id: &str,
        title: &str,
        command: &str,
        config_path: PathBuf,
    ) -> ExternalAgentStatus {
        let installed = executable_on_path(command);
        let config_ready = match id {
            "codex" => codex_config_ready(&config_path) && self.agents_file_path().is_file(),
            "claude" => {
                claude_config_ready(&config_path)
                    && self.agents_file_path().is_file()
                    && self.claude_instructions_path().is_file()
            }
            _ => false,
        };
        let status_detail = match (installed, config_ready) {
            (true, true) => "Ready".to_owned(),
            (true, false) => "CLI installed; workspace files need regeneration".to_owned(),
            (false, true) => "Workspace files ready; CLI not found in PATH".to_owned(),
            (false, false) => "CLI not found in PATH; workspace files need regeneration".to_owned(),
        };

        ExternalAgentStatus {
            id: id.to_owned(),
            title: title.to_owned(),
            cli_command: command.to_owned(),
            installed,
            config_ready,
            config_path: path_to_string(&config_path),
            status_detail,
        }
    }

    fn custom_agent_status(&self) -> ExternalAgentStatus {
        ExternalAgentStatus {
            id: "custom".to_owned(),
            title: "Custom Agent".to_owned(),
            cli_command: String::new(),
            installed: false,
            config_ready: false,
            config_path: path_to_string(&self.workspace_dir),
            status_detail: "Enter a custom CLI command to launch it in this workspace".to_owned(),
        }
    }

    fn ensure_shared_instructions(&self) -> AppResult<()> {
        let agents_body = format!(
            r#"{MANAGED_BLOCK_START}
# Kerminal External Agent Workspace

- Treat this directory as the Kerminal configuration workspace.
- Use the Kerminal MCP server for runtime actions: `{}`.
- Prefer editing file-backed configuration under `config/` after validating schema.
- Do not edit `secrets/` unless the user explicitly asks.
- Do not store API keys, tokens, passwords, or private keys in ordinary config files.
- Run the configured validator after changing Kerminal configuration files.
{MANAGED_BLOCK_END}
"#,
            self.mcp_endpoint
        );
        patch_managed_block(&self.agents_file_path(), &agents_body)?;
        Ok(())
    }

    fn ensure_codex_config(&self) -> AppResult<()> {
        let path = self.codex_config_path();
        let snippet = format!(
            r#"[mcp_servers.kerminal]
url = "{}"
default_tools_approval_mode = "prompt"
tool_timeout_sec = 60
enabled = true
"#,
            self.mcp_endpoint
        );
        let current = read_optional_string(&path)?;
        let next = replace_toml_table(
            &current.unwrap_or_default(),
            "[mcp_servers.kerminal]",
            &snippet,
        );
        write_if_changed(&path, &next)
    }

    fn ensure_claude_files(&self) -> AppResult<()> {
        let claude_body = format!(
            r#"{MANAGED_BLOCK_START}
@AGENTS.md

## Claude Code

- Treat this directory as the Kerminal configuration workspace.
- Use the Kerminal MCP server for runtime actions: `{}`.
- Do not edit `secrets/` unless the user explicitly asks.
{MANAGED_BLOCK_END}
"#,
            self.mcp_endpoint
        );
        patch_managed_block(&self.claude_instructions_path(), &claude_body)?;
        self.ensure_claude_mcp_json()
    }

    fn ensure_claude_mcp_json(&self) -> AppResult<()> {
        let path = self.claude_config_path();
        let mut root = match read_optional_string(&path)? {
            Some(content) if !content.trim().is_empty() => {
                serde_json::from_str::<Value>(&content).unwrap_or_else(|_| json!({}))
            }
            _ => json!({}),
        };
        let object = root
            .as_object_mut()
            .ok_or_else(|| AppError::InvalidInput(".mcp.json must be a JSON object".to_owned()))?;
        let servers = object
            .entry("mcpServers")
            .or_insert_with(|| Value::Object(Map::new()));
        let servers_object = servers.as_object_mut().ok_or_else(|| {
            AppError::InvalidInput(".mcp.json mcpServers must be a JSON object".to_owned())
        })?;
        servers_object.insert(
            "kerminal".to_owned(),
            json!({
                "type": "http",
                "url": self.mcp_endpoint,
                "timeout": 60000
            }),
        );
        let next = serde_json::to_string_pretty(&root)?;
        write_if_changed(&path, &format!("{next}\n"))
    }

    fn agents_file_path(&self) -> PathBuf {
        self.workspace_dir.join("AGENTS.md")
    }

    fn claude_instructions_path(&self) -> PathBuf {
        self.workspace_dir.join("CLAUDE.md")
    }

    fn codex_config_path(&self) -> PathBuf {
        self.workspace_dir.join(".codex").join("config.toml")
    }

    fn claude_config_path(&self) -> PathBuf {
        self.workspace_dir.join(".mcp.json")
    }
}

fn read_optional_string(path: &Path) -> AppResult<Option<String>> {
    match fs::read_to_string(path) {
        Ok(content) => Ok(Some(content)),
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => Ok(None),
        Err(error) => Err(error.into()),
    }
}

fn write_if_changed(path: &Path, content: &str) -> AppResult<()> {
    if read_optional_string(path)?.as_deref() == Some(content) {
        return Ok(());
    }
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent)?;
    }
    backup_existing_file(path)?;
    let temp_path = path.with_file_name(format!(
        ".{}.tmp-{}",
        path.file_name()
            .and_then(|name| name.to_str())
            .unwrap_or("kerminal"),
        Uuid::new_v4()
    ));
    fs::write(&temp_path, content)?;
    if path.exists() {
        fs::remove_file(path)?;
    }
    fs::rename(temp_path, path)?;
    Ok(())
}

fn backup_existing_file(path: &Path) -> AppResult<()> {
    if !path.is_file() {
        return Ok(());
    }
    let timestamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| duration.as_secs())
        .unwrap_or_default();
    let file_name = path
        .file_name()
        .and_then(|name| name.to_str())
        .unwrap_or("kerminal-file");
    let backup_path = path.with_file_name(format!("{file_name}.bak-{timestamp}"));
    fs::copy(path, backup_path)?;
    Ok(())
}

fn patch_managed_block(path: &Path, block: &str) -> AppResult<()> {
    let current = read_optional_string(path)?.unwrap_or_default();
    let next = if let Some(start) = current.find(MANAGED_BLOCK_START) {
        if let Some(end_relative) = current[start..].find(MANAGED_BLOCK_END) {
            let end = start + end_relative + MANAGED_BLOCK_END.len();
            format!(
                "{}{}{}",
                &current[..start],
                block.trim_end(),
                &current[end..]
            )
        } else {
            format!("{}\n\n{}", current.trim_end(), block.trim_end())
        }
    } else if current.trim().is_empty() {
        format!("{}\n", block.trim_end())
    } else {
        format!("{}\n\n{}\n", current.trim_end(), block.trim_end())
    };
    write_if_changed(path, &next)
}

fn replace_toml_table(content: &str, table_header: &str, replacement: &str) -> String {
    let lines = content.lines().collect::<Vec<_>>();
    let Some(start) = lines.iter().position(|line| line.trim() == table_header) else {
        let mut next = content.trim_end().to_owned();
        if !next.is_empty() {
            next.push_str("\n\n");
        }
        next.push_str(replacement.trim_end());
        next.push('\n');
        return next;
    };
    let end = lines
        .iter()
        .enumerate()
        .skip(start + 1)
        .find_map(|(index, line)| {
            let trimmed = line.trim();
            (trimmed.starts_with('[') && trimmed.ends_with(']')).then_some(index)
        })
        .unwrap_or(lines.len());
    let mut next_lines = Vec::new();
    next_lines.extend_from_slice(&lines[..start]);
    next_lines.extend(replacement.trim_end().lines());
    next_lines.extend_from_slice(&lines[end..]);
    format!("{}\n", next_lines.join("\n").trim_end())
}

fn codex_config_ready(path: &Path) -> bool {
    fs::read_to_string(path)
        .map(|content| content.contains("[mcp_servers.kerminal]") && content.contains("url = "))
        .unwrap_or(false)
}

fn claude_config_ready(path: &Path) -> bool {
    let Ok(content) = fs::read_to_string(path) else {
        return false;
    };
    let Ok(root) = serde_json::from_str::<Value>(&content) else {
        return false;
    };
    root.pointer("/mcpServers/kerminal/url")
        .and_then(Value::as_str)
        .is_some()
}

fn parse_command_line(input: &str) -> AppResult<(String, Vec<String>)> {
    let parts = split_command_line(input);
    let Some(shell) = parts.first().filter(|value| !value.trim().is_empty()) else {
        return Err(AppError::InvalidInput(
            "Custom agent command is not configured. Enter a command before launch.".to_owned(),
        ));
    };
    Ok((shell.clone(), parts[1..].to_vec()))
}

fn split_command_line(input: &str) -> Vec<String> {
    let chars = input.chars().collect::<Vec<_>>();
    let mut parts = Vec::new();
    let mut current = String::new();
    let mut quote: Option<char> = None;
    let mut index = 0;

    while index < chars.len() {
        let char = chars[index];
        if char == '\\' {
            if let Some(next) = chars.get(index + 1).copied() {
                if next == '"' || next == '\'' || next == '\\' || next.is_whitespace() {
                    current.push(next);
                    index += 2;
                    continue;
                }
            }
            current.push(char);
            index += 1;
            continue;
        }
        if let Some(active_quote) = quote {
            if char == active_quote {
                quote = None;
            } else {
                current.push(char);
            }
            index += 1;
            continue;
        }
        if char == '"' || char == '\'' {
            quote = Some(char);
            index += 1;
            continue;
        }
        if char.is_whitespace() {
            if !current.is_empty() {
                parts.push(std::mem::take(&mut current));
            }
            index += 1;
            continue;
        }
        current.push(char);
        index += 1;
    }

    if !current.is_empty() {
        parts.push(current);
    }
    parts
}

fn executable_on_path(command: &str) -> bool {
    let command_path = Path::new(command);
    if command_path.components().count() > 1 {
        return command_path.is_file();
    }
    let Some(path_value) = env::var_os("PATH") else {
        return false;
    };
    let candidates = executable_names(command);
    env::split_paths(&path_value).any(|directory| {
        candidates
            .iter()
            .any(|candidate| directory.join(candidate).is_file())
    })
}

fn executable_names(command: &str) -> Vec<OsString> {
    #[cfg(windows)]
    {
        let command_path = Path::new(command);
        if command_path.extension().is_some() {
            return vec![OsString::from(command)];
        }
        let path_ext = env::var_os("PATHEXT")
            .and_then(|value| value.into_string().ok())
            .unwrap_or_else(|| ".COM;.EXE;.BAT;.CMD".to_owned());
        return path_ext
            .split(';')
            .filter(|extension| !extension.trim().is_empty())
            .map(|extension| OsString::from(format!("{command}{extension}")))
            .chain(std::iter::once(OsString::from(command)))
            .collect();
    }
    #[cfg(not(windows))]
    {
        vec![OsString::from(command)]
    }
}

fn path_to_string(path: &Path) -> String {
    path.to_string_lossy().into_owned()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn prepare_codex_writes_managed_files_without_clobbering_user_content() {
        let temp = tempfile::tempdir().expect("tempdir");
        let service = ExternalAgentWorkspaceService::new(
            temp.path(),
            Some("http://127.0.0.1:3000/mcp".to_owned()),
            true,
        );
        fs::write(temp.path().join("AGENTS.md"), "# User notes\n").expect("seed agents");

        let spec = service
            .prepare(&PrepareExternalAgentWorkspaceRequest {
                agent_id: "codex".to_owned(),
                custom_command: None,
            })
            .expect("prepare codex");

        assert_eq!(spec.shell, "codex");
        assert_eq!(spec.cwd, path_to_string(temp.path()));
        let agents = fs::read_to_string(temp.path().join("AGENTS.md")).expect("agents");
        assert!(agents.contains("# User notes"));
        assert!(agents.contains(MANAGED_BLOCK_START));
        let codex =
            fs::read_to_string(temp.path().join(".codex").join("config.toml")).expect("codex");
        assert!(codex.contains("[mcp_servers.kerminal]"));
        assert!(codex.contains("http://127.0.0.1:3000/mcp"));
    }

    #[test]
    fn default_initialization_writes_only_codex_and_claude_files() {
        let temp = tempfile::tempdir().expect("tempdir");
        let service = ExternalAgentWorkspaceService::new(
            temp.path(),
            Some("http://127.0.0.1:3002/mcp".to_owned()),
            false,
        );

        service.ensure_default_agent_files().expect("default files");

        assert!(temp.path().join("AGENTS.md").is_file());
        assert!(temp.path().join("CLAUDE.md").is_file());
        assert!(temp.path().join(".codex").join("config.toml").is_file());
        assert!(temp.path().join(".mcp.json").is_file());
        assert!(!temp.path().join("custom-agent.toml").exists());
        assert!(!temp.path().join(".custom-agent").exists());
    }

    #[test]
    fn prepare_claude_merges_mcp_json() {
        let temp = tempfile::tempdir().expect("tempdir");
        fs::write(
            temp.path().join(".mcp.json"),
            r#"{"mcpServers":{"other":{"type":"http","url":"http://x"}}}"#,
        )
        .expect("seed mcp");
        let service = ExternalAgentWorkspaceService::new(
            temp.path(),
            Some("http://127.0.0.1:3001/mcp".to_owned()),
            true,
        );

        let spec = service
            .prepare(&PrepareExternalAgentWorkspaceRequest {
                agent_id: "claude".to_owned(),
                custom_command: None,
            })
            .expect("prepare claude");

        assert_eq!(spec.shell, "claude");
        let root: Value =
            serde_json::from_str(&fs::read_to_string(temp.path().join(".mcp.json")).expect("mcp"))
                .expect("json");
        assert_eq!(
            root.pointer("/mcpServers/other/url")
                .and_then(Value::as_str),
            Some("http://x")
        );
        assert_eq!(
            root.pointer("/mcpServers/kerminal/url")
                .and_then(Value::as_str),
            Some("http://127.0.0.1:3001/mcp")
        );
        let claude = fs::read_to_string(temp.path().join("CLAUDE.md")).expect("claude");
        assert!(claude.contains("@AGENTS.md"));
    }

    #[test]
    fn prepare_custom_uses_explicit_command_without_default_files() {
        let temp = tempfile::tempdir().expect("tempdir");
        let service = ExternalAgentWorkspaceService::new(
            temp.path(),
            Some("http://127.0.0.1:3003/mcp".to_owned()),
            true,
        );

        let spec = service
            .prepare(&PrepareExternalAgentWorkspaceRequest {
                agent_id: "custom".to_owned(),
                custom_command: Some("qwen --model max".to_owned()),
            })
            .expect("prepare custom");

        assert_eq!(spec.shell, "qwen");
        assert_eq!(spec.args, vec!["--model", "max"]);
        assert_eq!(spec.cwd, path_to_string(temp.path()));
        assert!(!temp.path().join("custom-agent.toml").exists());
        assert!(!temp.path().join(".custom-agent").exists());
        assert!(!temp.path().join(".codex").exists());
        assert!(!temp.path().join(".mcp.json").exists());
    }

    #[test]
    fn custom_command_parser_preserves_windows_paths() {
        let (shell, args) = parse_command_line(r#"C:\Tools\kimi.exe --fast"#).expect("plain path");
        assert_eq!(shell, r#"C:\Tools\kimi.exe"#);
        assert_eq!(args, vec!["--fast"]);

        let (shell, args) =
            parse_command_line(r#""C:\Program Files\Kimi\kimi.exe" --fast"#).expect("quoted path");
        assert_eq!(shell, r#"C:\Program Files\Kimi\kimi.exe"#);
        assert_eq!(args, vec!["--fast"]);
    }

    #[test]
    fn replace_toml_table_replaces_only_kerminal_table() {
        let content = r#"[profile]
name = "keep"

[mcp_servers.kerminal]
url = "old"

[mcp_servers.other]
url = "other"
"#;
        let next = replace_toml_table(
            content,
            "[mcp_servers.kerminal]",
            "[mcp_servers.kerminal]\nurl = \"new\"",
        );

        assert!(next.contains("name = \"keep\""));
        assert!(next.contains("url = \"new\""));
        assert!(next.contains("[mcp_servers.other]"));
        assert!(!next.contains("url = \"old\""));
    }
}

