export function AgentLauncherToolContent({
  resolvedTheme = "dark",
  terminalAppearance = defaultTerminalAppearance,
}: AgentLauncherToolContentProps) {
  const [status, setStatus] = useState<ExternalAgentWorkspaceStatus | null>(
    null,
  );
  const [loadState, setLoadState] = useState<LoadState>("loading");
  const [loadError, setLoadError] = useState<string | null>(null);
  const [actionState, setActionState] = useState<ActionState>(null);
  const [actionError, setActionError] = useState<string | null>(null);
  const [customCommandOpen, setCustomCommandOpen] = useState(false);
  const [customCommand, setCustomCommand] = useState("");
  const [activeTerminal, setActiveTerminal] =
    useState<ActiveAgentTerminal | null>(null);

  const loadStatus = useCallback(async (state: LoadState = "loading") => {
    setLoadState(state);
    setLoadError(null);
    try {
      setStatus(await getExternalAgentWorkspaceStatus());
      setLoadState("idle");
    } catch (error) {
      setLoadError(agentLauncherErrorMessage(error));
      setLoadState("error");
    }
  }, []);

  useEffect(() => {
    void loadStatus("loading");
  }, [loadStatus]);

  const agentActions = useMemo(
    () => (status ? buildAgentLauncherViewModel(status, true) : initialAgentActions),
    [status],
  );

  const runAction = async (
    nextAction: ExternalAgentId,
    action: () => Promise<void>,
  ) => {
    setActionState(nextAction);
    setActionError(null);
    try {
      await action();
    } catch (error) {
      setActionError(agentLauncherErrorMessage(error));
    } finally {
      setActionState(null);
    }
  };

  const launchPreparedSpec = (spec: ExternalAgentLaunchSpec) => {
    setActiveTerminal({
      agentId: spec.agentId,
      args: spec.args ?? [],
      cwd: spec.cwd,
      env: spec.env,
      id: Date.now(),
      shell: spec.shell,
      title: spec.title,
    });
  };

  const launchAgent = (agentId: ExternalAgentId) => {
    if (agentId === "custom") {
      setCustomCommandOpen(true);
      setActionError(null);
      return;
    }

    void runAction(agentId, async () => {
      const launchSpec = await prepareExternalAgentWorkspace({ agentId });
      launchPreparedSpec(launchSpec);
      await loadStatus("refreshing");
    });
  };

  const launchCustomAgent = () => {
    void runAction("custom", async () => {
      const launchSpec = await prepareExternalAgentWorkspace({
        agentId: "custom",
        customCommand: customCommand.trim(),
      });
      setActiveTerminal({
        agentId: "custom",
        args: launchSpec.args ?? [],
        cwd: launchSpec.cwd,
        env: launchSpec.env,
        id: Date.now(),
        shell: launchSpec.shell,
        title: launchSpec.shell,
      });
      await loadStatus("refreshing");
    });
  };

  if (activeTerminal) {
    return (
      <AgentTerminalView
        session={activeTerminal}
        onBack={() => setActiveTerminal(null)}
        resolvedTheme={resolvedTheme}
        terminalAppearance={terminalAppearance}
      />
    );
  }

  return (
    <section className="flex h-full min-h-0 flex-col overflow-hidden">
      <div className="flex min-h-0 flex-1 flex-col px-4 py-5">
        <div className="flex min-h-0 flex-1 items-center justify-center">
          <div className="w-full max-w-[320px]">
            <div className="grid grid-cols-3 gap-2">
              {agentActions.map((agent) => (
                <AgentIconButton
                  actionState={actionState}
                  agent={agent}
                  key={agent.agentId}
                  onLaunch={launchAgent}
                />
              ))}
            </div>

            {customCommandOpen ? (
              <form
                className="mt-4 flex items-center gap-2 rounded-[18px] border border-[var(--border-subtle)] bg-[var(--surface-hover)] p-2"
                onSubmit={(event) => {
                  event.preventDefault();
                  launchCustomAgent();
                }}
              >
                <label className="sr-only">
                  Custom CLI command
                </label>
                <input
                  aria-label="Custom agent command"
                  autoFocus
                  className="h-9 min-w-0 flex-1 rounded-xl border border-transparent bg-transparent px-2 font-mono text-sm text-zinc-900 outline-none transition placeholder:text-zinc-400 focus:border-sky-400 focus:bg-white/70 focus:ring-4 focus:ring-sky-400/15 dark:text-zinc-50 dark:placeholder:text-zinc-500 dark:focus:bg-white/10"
                  onChange={(event) => setCustomCommand(event.target.value)}
                  placeholder="kimi or qwen --model ..."
                  value={customCommand}
                />
                <Button
                  aria-label="Open custom agent command"
                  disabled={actionState !== null || !customCommand.trim()}
                  size="icon"
                  type="submit"
                  variant="primary"
                >
                  {actionState === "custom" ? (
                    <Loader2 className="h-4 w-4 animate-spin" />
                  ) : (
                    <Terminal className="h-4 w-4" />
                  )}
                </Button>
              </form>
            ) : null}
          </div>
        </div>

        {loadState === "error" && !status ? (
          <InlineError message={loadError ?? "Agent workspace unavailable."}>
            <Button onClick={() => void loadStatus("loading")} size="sm">
              Retry
            </Button>
          </InlineError>
        ) : null}
        {actionError ? <InlineError message={actionError} /> : null}
      </div>
    </section>
  );
}

