import type {
  ExternalAgentId,
  ExternalAgentStatus,
  ExternalAgentWorkspaceStatus,
} from "../../../lib/agentLauncherApi";
export type { ParsedAgentCommand } from "../../../lib/agentCommandLine";
export { parseAgentCommandLine } from "../../../lib/agentCommandLine";

export const EXTERNAL_AGENT_IDS: ExternalAgentId[] = [
  "codex",
  "claude",
  "custom",
];
export const EXTERNAL_AGENT_WORKSPACE_FILE_AGENT_IDS: ExternalAgentId[] = [
  "codex",
  "claude",
];

export type AgentLauncherTone = "ready" | "warning" | "danger" | "muted";

export interface McpStatusViewModel {
  label: string;
  detail: string;
  tone: AgentLauncherTone;
}

export interface AgentActionViewModel {
  agentId: ExternalAgentId;
  title: string;
  cliCommand: string;
  configPath: string;
  statusDetail: string;
  installLabel: string;
  configLabel: string;
  actionLabel: string;
  disabled: boolean;
  disabledReason?: string;
  tone: AgentLauncherTone;
}

interface AgentActionOptions {
  mcpServerRunning: boolean;
  terminalLauncherAvailable: boolean;
}

export function buildAgentLauncherViewModel(
  status: ExternalAgentWorkspaceStatus,
  terminalLauncherAvailable: boolean,
): AgentActionViewModel[] {
  return EXTERNAL_AGENT_IDS.map((agentId) =>
    buildAgentActionViewModel(status.agents[agentId], {
      mcpServerRunning: status.mcpServerRunning,
      terminalLauncherAvailable,
    }),
  );
}

export function buildAgentActionViewModel(
  agent: ExternalAgentStatus,
  options: AgentActionOptions,
): AgentActionViewModel {
  const disabledReason = resolveAgentDisabledReason(agent, options);
  const customAgent = agent.id === "custom";
  const commandConfigured = Boolean(agent.cliCommand.trim());
  const configReady = customAgent ? true : agent.configReady;
  const installed = agent.installed;
  const statusDetail =
    !customAgent && !options.mcpServerRunning
      ? "Kerminal MCP Server will be started before launch."
      : agent.statusDetail.trim() ||
        (customAgent
          ? "Custom Agent uses an explicit launch command and no default workspace config files."
          : installed
            ? `${agent.title} is ready to use the Kerminal MCP endpoint.`
            : `${agent.title} CLI was not detected on PATH.`);

  return {
    actionLabel: customAgent
      ? `Open ${agent.title}`
      : !options.mcpServerRunning
        ? `Start & Open ${agent.title}`
        : configReady
          ? `Open ${agent.title}`
          : "Prepare & Open",
    agentId: agent.id,
    cliCommand: agent.cliCommand.trim() || "No command configured",
    configLabel: customAgent
      ? commandConfigured
        ? "Explicit command"
        : "Enter command"
      : configReady
        ? "Config ready"
        : "Config needs update",
    configPath: customAgent
      ? "User supplied CLI"
      : agent.configPath.trim() || "Config path not generated",
    disabled: Boolean(disabledReason),
    disabledReason,
    installLabel: installed ? "Installed" : "Missing CLI",
    statusDetail,
    title: agent.title,
    tone: resolveAgentTone(agent, disabledReason),
  };
}

export function getMcpStatusView(
  status: Pick<
    ExternalAgentWorkspaceStatus,
    "mcpEndpoint" | "mcpServerRunning"
  >,
): McpStatusViewModel {
  if (status.mcpServerRunning) {
    return {
      detail: status.mcpEndpoint || "Endpoint is not available yet.",
      label: "Running",
      tone: "ready",
    };
  }

  return {
    detail: "Start Kerminal MCP Server before launching external agents.",
    label: "Stopped",
    tone: "danger",
  };
}

export function buildAgentConfigSnippet(
  status: Pick<ExternalAgentWorkspaceStatus, "mcpEndpoint">,
): string {
  const endpoint = status.mcpEndpoint || "http://127.0.0.1:14251/mcp";
  return [
    "# Codex: ~/.kerminal/.codex/config.toml",
    "[mcp_servers.kerminal]",
    `url = "${endpoint}"`,
    'default_tools_approval_mode = "prompt"',
    "tool_timeout_sec = 60",
    "enabled = true",
    "",
    "# Claude: ~/.kerminal/.mcp.json",
    JSON.stringify(
      {
        mcpServers: {
          kerminal: {
            timeout: 60000,
            type: "http",
            url: endpoint,
          },
        },
      },
      null,
      2,
    ),
  ].join("\n");
}

export function formatAgentLauncherPath(path: string): string {
  return path.trim() || "Not generated yet";
}

export function agentLauncherErrorMessage(error: unknown): string {
  return error instanceof Error ? error.message : String(error);
}

function resolveAgentDisabledReason(
  agent: ExternalAgentStatus,
  options: AgentActionOptions,
): string | undefined {
  if (!options.terminalLauncherAvailable) {
    return "Terminal launcher is unavailable.";
  }
  if (agent.id === "custom") {
    return undefined;
  }
  if (!agent.cliCommand.trim()) {
    return "No launch command is configured.";
  }
  return undefined;
}

function resolveAgentTone(
  agent: ExternalAgentStatus,
  disabledReason: string | undefined,
): AgentLauncherTone {
  if (disabledReason) {
    return agent.installed ? "danger" : "warning";
  }
  if (agent.id === "custom") {
    return "ready";
  }
  if (!agent.installed) {
    return "warning";
  }
  if (!agent.configReady) {
    return "warning";
  }
  return "ready";
}

import { invoke, isTauri } from "@tauri-apps/api/core";
import { parseAgentCommandLine } from "./agentCommandLine";

export type ExternalAgentId = "codex" | "claude" | "custom";

export interface ExternalAgentStatus {
  id: ExternalAgentId;
  title: string;
  cliCommand: string;
  installed: boolean;
  configReady: boolean;
  configPath: string;
  statusDetail: string;
}

export interface ExternalAgentWorkspaceStatus {
  workspaceDir: string;
  mcpEndpoint: string;
  mcpServerRunning: boolean;
  agents: Record<ExternalAgentId, ExternalAgentStatus>;
}

export interface PrepareExternalAgentWorkspaceRequest {
  agentId: ExternalAgentId;
  customCommand?: string;
}

export interface ExternalAgentLaunchSpec {
  agentId: ExternalAgentId;
  title: string;
  shell: string;
  args: string[];
  cwd: string;
  env?: Record<string, string>;
  message: string;
}

export function getExternalAgentWorkspaceStatus(): Promise<ExternalAgentWorkspaceStatus> {
  if (!isTauri()) {
    return Promise.resolve(previewExternalAgentWorkspaceStatus());
  }

  return invoke<ExternalAgentWorkspaceStatus>(
    "get_external_agent_workspace_status",
  );
}

export function prepareExternalAgentWorkspace(
  request: PrepareExternalAgentWorkspaceRequest,
): Promise<ExternalAgentLaunchSpec> {
  if (!isTauri()) {
    return Promise.resolve(previewExternalAgentLaunchSpec(request));
  }

  return invoke<ExternalAgentLaunchSpec>("prepare_external_agent_workspace", {
    request,
  });
}

function previewExternalAgentWorkspaceStatus(): ExternalAgentWorkspaceStatus {
  const workspaceDir = "~/.kerminal";
  const endpoint = "http://127.0.0.1:37657/mcp";
  return {
    agents: {
      claude: {
        cliCommand: "claude",
        configPath: `${workspaceDir}/.mcp.json`,
        configReady: true,
        id: "claude",
        installed: false,
        statusDetail: "Claude CLI was not detected in browser preview.",
        title: "Claude",
      },
      codex: {
        cliCommand: "codex",
        configPath: `${workspaceDir}/.codex/config.toml`,
        configReady: true,
        id: "codex",
        installed: false,
        statusDetail: "Codex CLI was not detected in browser preview.",
        title: "Codex",
      },
      custom: {
        cliCommand: "",
        configPath: "",
        configReady: false,
        id: "custom",
        installed: false,
        statusDetail: "Custom Agent is not initialized by default.",
        title: "Custom",
      },
    },
    mcpEndpoint: endpoint,
    mcpServerRunning: false,
    workspaceDir,
  };
}

function previewExternalAgentLaunchSpec({
  agentId,
  customCommand,
}: PrepareExternalAgentWorkspaceRequest): ExternalAgentLaunchSpec {
  const status = previewExternalAgentWorkspaceStatus();
  const agent = status.agents[agentId];
  const custom = agentId === "custom";
  const parsed = custom ? parseAgentCommandLine(customCommand ?? "") : null;
  return {
    agentId,
    args: parsed?.args ?? [],
    cwd: status.workspaceDir,
    shell: parsed?.shell ?? agent.cliCommand,
    title: agent.title,
    message: `${agent.title} preview launch prepared.`,
  };
}
